const dns = require('dns');
const net = require('net');

const host = 'srvoraclebr04.citelsoftware.com.br';
const results = {};

// 1. DNS Lookup
try {
  const addresses = await new Promise((resolve, reject) => {
    dns.lookup(host, { all: true }, (err, addresses) => {
      if (err) reject(err);
      else resolve(addresses);
    });
  });
  results.dns = { status: 'ok', addresses };
} catch(e) {
  results.dns = { status: 'error', message: e.message, code: e.code };
}

// 2. Port test Marcel (60120)
try {
  await new Promise((resolve, reject) => {
    const socket = new net.Socket();
    socket.setTimeout(5000);
    socket.on('connect', () => { results.marcel_port = 'OPEN'; socket.destroy(); resolve(); });
    socket.on('timeout', () => { results.marcel_port = 'TIMEOUT'; socket.destroy(); resolve(); });
    socket.on('error', (e) => { results.marcel_port = 'ERROR: ' + e.code; resolve(); });
    socket.connect(60120, host);
  });
} catch(e) {
  results.marcel_port = 'EXCEPTION: ' + e.message;
}

// 3. Port test Alberto (50010)
try {
  await new Promise((resolve, reject) => {
    const socket = new net.Socket();
    socket.setTimeout(5000);
    socket.on('connect', () => { results.alberto_port = 'OPEN'; socket.destroy(); resolve(); });
    socket.on('timeout', () => { results.alberto_port = 'TIMEOUT'; socket.destroy(); resolve(); });
    socket.on('error', (e) => { results.alberto_port = 'ERROR: ' + e.code; resolve(); });
    socket.connect(50010, host);
  });
} catch(e) {
  results.alberto_port = 'EXCEPTION: ' + e.message;
}

return [{ json: results }];

